// app.js
import { Client, Storage, ID, Permission, Role } from "appwrite";

const client = new Client()
  .setEndpoint("https://<REGION>.cloud.appwrite.io/v1") // or your self-hosted endpoint
  .setProject("<PROJECT_ID>");

const storage = new Storage(client);

async function run() {
  // 1) Create bucket (requires a privileged/authenticated context)
  //    In production, do this in a trusted environment (Function/server), not public browser code.
  const bucket = await storage.createBucket({
    bucketId: ID.unique(),
    name: "images-bucket",
    fileSecurity: true, // enables per-file permissions
    permissions: [
      Permission.read(Role.any()),                 // anyone can read bucket metadata
      Permission.create(Role.users()),             // signed-in users can upload
      Permission.update(Role.team("editors")),     // team editors can update bucket
      Permission.delete(Role.team("admins")),      // team admins can delete bucket
    ],
    maximumFileSize: 10 * 1024 * 1024, // 10 MB
    allowedFileExtensions: ["jpg", "jpeg", "png", "webp"],
    compression: "gzip",
    encryption: true,
    antivirus: true,
    enabled: true,
  });

  const bucketId = bucket.$id;

  // 2) Upload file with file-level permissions
  const input = document.getElementById("fileInput");
  input.addEventListener("change", async () => {
    const file = input.files?.[0];
    if (!file) return;

    const uploaded = await storage.createFile({
      bucketId,
      fileId: ID.unique(),
      file,
      permissions: [
        Permission.read(Role.any()),         // public image
        Permission.update(Role.user("me")),  // owner can update
        Permission.delete(Role.user("me")),  // owner can delete
      ],
    });

    // 3) Get preview URL (for images)
    const previewUrl = storage.getFilePreview({
      bucketId,
      fileId: uploaded.$id,
      width: 600,
      height: 600,
      quality: 80,
    });

    document.getElementById("preview").src = previewUrl.toString();
    console.log("Preview URL:", previewUrl.toString());
  });
}

run().catch(console.error);
```

### Notes
- `createBucket` is usually done once (admin/trusted flow), not every page load.
- If you don’t need per-file ACLs, set `fileSecurity: false` and skip file `permissions` (files inherit bucket access).

Use one `subscribe` with an array of channels:

```js
client.subscribe(
  [
    `databases.${databaseId}.collections.${collectionId}.documents`,
    `buckets.${bucketId}.files`
  ],
  (response) => {
    console.log(response);
  }
);
```

The exact channel string patterns are:

- **Collection documents:** `databases.{databaseId}.collections.{collectionId}.documents`
- **Bucket files:** `buckets.{bucketId}.files`

```html
<script type="module">
  import { Client } from "https://cdn.jsdelivr.net/npm/appwrite@14.0.1/+esm";

  const client = new Client()
    .setEndpoint("https://<REGION>.cloud.appwrite.io/v1") // or your self-hosted endpoint
    .setProject("<PROJECT_ID>");

  const DATABASE_ID = "<DATABASE_ID>";
  const COLLECTION_ID = "<COLLECTION_ID>";
  const BUCKET_ID = "<BUCKET_ID>";

  // Subscribe to both channels at once
  const unsubscribe = client.subscribe(
    [
      `databases.${DATABASE_ID}.collections.${COLLECTION_ID}.documents`,
      `buckets.${BUCKET_ID}.files`,
    ],
    (message) => {
      const events = message.events || [];
      const event = events[0] || ""; // e.g. "...documents...update" or "...files...create"

      // Handle document create/update/delete
      if (event.includes(".documents.")) {
        if (event.endsWith(".create")) {
          console.log("Document created:", message.payload);
          // handle new document
        } else if (event.endsWith(".update")) {
          console.log("Document updated:", message.payload);
          // handle updated document
        } else if (event.endsWith(".delete")) {
          console.log("Document deleted:", message.payload);
          // handle deleted document
        }
        return;
      }

      // Handle file uploads (file create in bucket)
      if (event.includes(".files.") && event.endsWith(".create")) {
        console.log("File uploaded:", message.payload);
        // handle uploaded file (e.g., show toast, refresh file list)
        return;
      }

      // Optional: handle other file events (update/delete)
      if (event.includes(".files.")) {
        console.log("Other file event:", event, message.payload);
      }
    }
  );

  // Later (cleanup): stop listening
  // unsubscribe();
</script>
```

