# Email/Password Authentication with Appwrite Web SDK

## Installation

```bash
npm install appwrite
```

## Implementation

```javascript
import { Client, Account, ID } from 'appwrite';

// 1. Set up the Appwrite Client
const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Your Appwrite endpoint
    .setProject('<YOUR_PROJECT_ID>');             // Your Project ID

const account = new Account(client);

// 2. Sign Up - Create a new account
async function signup(email, password, name) {
    try {
        const newAccount = await account.create(
            ID.unique(),  // userId - auto-generate unique ID
            email,
            password,
            name          // optional
        );
        console.log('Account created:', newAccount);
        return newAccount;
    } catch (error) {
        console.error('Signup failed:', error.message);
        throw error;
    }
}

// 3. Login - Create an email/password session
async function login(email, password) {
    try {
        const session = await account.createEmailPasswordSession(email, password);
        console.log('Session created:', session);
        return session;
    } catch (error) {
        console.error('Login failed:', error.message);
        throw error;
    }
}

// 4. Get the currently logged-in user
async function getCurrentUser() {
    try {
        const user = await account.get();
        console.log('Current user:', user);
        return user;
    } catch (error) {
        console.error('Not logged in:', error.message);
        return null;
    }
}

// 5. Logout - Delete the current session
async function logout() {
    try {
        await account.deleteSession('current');
        console.log('Logged out successfully');
    } catch (error) {
        console.error('Logout failed:', error.message);
        throw error;
    }
}

// --- Usage ---
// Sign up a new user, then immediately log them in
async function signupAndLogin() {
    await signup('user@example.com', 'password123', 'John Doe');
    await login('user@example.com', 'password123');
    const user = await getCurrentUser();
    console.log('Authenticated as:', user.name);
}

signupAndLogin();
```

## Key Points

- **`account.create()`** registers a new user but does **not** create a session. The user still needs to log in afterward.
- **`account.createEmailPasswordSession()`** authenticates the user and creates a session (sets a session cookie/token).
- **`ID.unique()`** generates a unique ID for the new user. You can also pass your own custom string ID.
- **Password requirements**: Must be between **8 and 256 characters** long.
- **`account.deleteSession('current')`** deletes only the current session. Use **`account.deleteSessions()`** to revoke all sessions for the user.
- The session is automatically managed via cookies in a browser environment, so subsequent API calls are authenticated without manually passing tokens.

# Creating a Database, Collection, and Document with Appwrite Web SDK

Here's a complete example using the Appwrite Web SDK to set up a tasks collection and insert a document.

## 1. Setup & Initialize the Client

```javascript
import { Client, Databases, ID, Permission, Role } from 'appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Your Appwrite endpoint
    .setProject('<YOUR_PROJECT_ID>');             // Your project ID

const databases = new Databases(client);
```

## 2. Create the Database

```javascript
async function createDatabase() {
    try {
        const database = await databases.create(
            ID.unique(),
            'TasksDB' // Database name
        );
        console.log('Database created:', database.$id);
        return database;
    } catch (error) {
        console.error('Error creating database:', error);
        throw error;
    }
}
```

## 3. Create the Collection and Attributes

```javascript
async function createCollection(databaseId) {
    try {
        // Create the collection
        const collection = await databases.createCollection(
            databaseId,
            ID.unique(),
            'tasks',
            [
                Permission.read(Role.any()),
                Permission.create(Role.users()),
                Permission.update(Role.users()),
                Permission.delete(Role.users())
            ]
        );
        console.log('Collection created:', collection.$id);

        // Create "title" string attribute
        await databases.createStringAttribute(
            databaseId,
            collection.$id,
            'title',       // key
            255,           // size (max length)
            true           // required
        );
        console.log('Attribute "title" created');

        // Create "completed" boolean attribute
        await databases.createBooleanAttribute(
            databaseId,
            collection.$id,
            'completed',   // key
            true,          // required
            false          // default value
        );
        console.log('Attribute "completed" created');

        // Create "dueDate" datetime attribute
        await databases.createDatetimeAttribute(
            databaseId,
            collection.$id,
            'dueDate',     // key
            false          // required
        );
        console.log('Attribute "dueDate" created');

        return collection;
    } catch (error) {
        console.error('Error creating collection/attributes:', error);
        throw error;
    }
}
```

## 4. Insert a Document

```javascript
async function createDocument(databaseId, collectionId) {
    try {
        const document = await databases.createDocument(
            databaseId,
            collectionId,
            ID.unique(),
            {
                title: 'Finish Appwrite tutorial',
                completed: false,
                dueDate: new Date('2025-03-15T10:00:00.000Z').toISOString()
            }
        );
        console.log('Document created:', document);
        return document;
    } catch (error) {
        console.error('Error creating document:', error);
        throw error;
    }
}
```

## 5. Run Everything Together

```javascript
async function main() {
    try {
        // Step 1: Create the database
        const database = await createDatabase();

        // Step 2: Create collection and attributes
        const collection = await createCollection(database.$id);

        // Step 3: Wait for attributes to be processed
        // Attributes are created asynchronously on the server.
        // In production, poll the collection or use a delay.
        console.log('Waiting for attributes to be ready...');
        await new Promise((resolve) => setTimeout(resolve, 3000));

        // Step 4: Insert a document
        const document = await createDocument(database.$id, collection.$id);

        console.log('All done!');
        console.log('Database ID:', database.$id);
        console.log('Collection ID:', collection.$id);
        console.log('Document ID:', document.$id);
    } catch (error) {
        console.error('Setup failed:', error);
    }
}

main();
```

## Important Notes

- **Attribute processing delay**: Attributes are created asynchronously on the Appwrite server. The `setTimeout` ensures they're available before inserting a document. In production, you should poll the collection status and check that all attributes have `status: 'available'`.
- **Permissions**: The example grants read access to anyone and write access to authenticated users. Adjust `Permission` rules based on your security requirements.
- **API Key vs. Client Auth**: Creating databases and collections typically requires **server-side** privileges (an API key via the Server SDK). If you're running this from a browser, ensure the authenticated user has the appropriate scopes, or use the **Node.js Server SDK** for the setup steps and the Web SDK only for document operations.

# Querying Documents in Appwrite

The `Query` class provides a powerful way to filter, sort, and paginate documents in Appwrite databases.

## Basic Query Structure

Queries are passed as an array to the `listDocuments` method:

```javascript
import { Client, Databases, Query } from 'appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('<PROJECT_ID>');

const databases = new Databases(client);

const response = await databases.listDocuments(
    '<DATABASE_ID>',
    '<COLLECTION_ID>',
    [
        // Queries go here
    ]
);
```

## Filtering

### Equal / Not Equal
```javascript
// Exact match
Query.equal('status', 'active')
Query.equal('status', ['active', 'pending'])  // matches any value in array

// Not equal
Query.notEqual('status', 'archived')
```

### Comparison Operators
```javascript
Query.greaterThan('price', 100)
Query.greaterThanEqual('price', 100)
Query.lessThan('price', 500)
Query.lessThanEqual('price', 500)
Query.between('price', 100, 500)
```

### String Searches
```javascript
Query.startsWith('name', 'John')
Query.endsWith('email', '@gmail.com')
Query.contains('tags', 'javascript')    // checks if array attribute contains value
Query.search('content', 'hello world')  // full-text search (requires full-text index)
```

### Null Checks
```javascript
Query.isNull('deletedAt')
Query.isNotNull('assignedTo')
```

## Sorting

```javascript
Query.orderAsc('createdAt')
Query.orderDesc('price')

// Multiple sort criteria
[
    Query.orderAsc('lastName'),
    Query.orderAsc('firstName')
]
```

## Limiting and Offset

```javascript
// Limit results
Query.limit(25)

// Skip results (offset)
Query.offset(50)
```

## Cursor-Based Pagination

Cursor pagination is more performant than offset for large datasets:

```javascript
// Get the next page after a specific document ID
Query.cursorAfter('<DOCUMENT_ID>')

// Get the previous page before a specific document ID
Query.cursorBefore('<DOCUMENT_ID>')
```

## Selecting Specific Attributes

```javascript
Query.select(['name', 'email', 'status'])
```

## Combining Queries (AND Logic)

All queries in the array are combined with **AND** logic:

```javascript
const response = await databases.listDocuments(
    '<DATABASE_ID>',
    '<COLLECTION_ID>',
    [
        Query.equal('status', 'active'),
        Query.greaterThan('price', 50),
        Query.lessThanEqual('price', 200),
        Query.orderDesc('price'),
        Query.limit(20)
    ]
);
```

## OR Queries

Use `Query.or()` to combine conditions with OR logic:

```javascript
const response = await databases.listDocuments(
    '<DATABASE_ID>',
    '<COLLECTION_ID>',
    [
        Query.or([
            Query.equal('status', 'active'),
            Query.equal('status', 'pending')
        ])
    ]
);
```

## Full Pagination Example

```javascript
async function getPaginatedResults(databaseId, collectionId) {
    let allDocuments = [];
    let lastDocumentId = null;
    const pageSize = 100;

    while (true) {
        const queries = [
            Query.limit(pageSize),
            Query.orderDesc('$createdAt')
        ];

        if (lastDocumentId) {
            queries.push(Query.cursorAfter(lastDocumentId));
        }

        const response = await databases.listDocuments(
            databaseId,
            collectionId,
            queries
        );

        allDocuments = allDocuments.concat(response.documents);

        if (response.documents.length < pageSize) {
            break; // No more documents
        }

        lastDocumentId = response.documents[response.documents.length - 1].$id;
    }

    return allDocuments;
}
```

## Important Notes

- **Indexes are required**: Queries only work on attributes that have appropriate indexes configured in your collection. Without an index, the query will return an error.
- **Default limit**: If no limit is specified, Appwrite returns a default of **25 documents**.
- **Maximum limit**: The maximum value for `Query.limit()` is **5000**.
- **`response.total`**: The response includes a `total` field indicating the total number of documents matching the filter (ignoring limit/offset), useful for building pagination UIs.

# Appwrite Function: Personalized Greeting

Here's an Appwrite Function in Node.js that receives a JSON body with a `name` field and returns a personalized greeting:

```javascript
export default async ({ req, res, log, error }) => {
  // Handle the request
  if (req.method === 'POST') {
    try {
      // The body is automatically parsed if Content-Type is application/json
      const { name } = req.body;

      if (!name) {
        return res.json(
          { ok: false, message: 'Missing required field: "name"' },
          400
        );
      }

      log(`Greeting requested for: ${name}`);

      return res.json({
        ok: true,
        greeting: `Hello, ${name}! Welcome to Appwrite Functions!`,
      });
    } catch (err) {
      error(`Error processing request: ${err.message}`);
      return res.json(
        { ok: false, message: 'Failed to process request' },
        500
      );
    }
  }

  // Handle non-POST requests
  return res.json(
    { ok: false, message: 'Method not allowed. Please use POST.' },
    405
  );
};
```

## Key Details

- **Function Signature**: The entry point uses `export default async ({ req, res, log, error })` — this is the required signature for Appwrite Functions (Node.js runtime `node-18.0` and above).
- **`req.body`**: Appwrite automatically parses the JSON body when the `Content-Type: application/json` header is set. No need to call `JSON.parse()` manually.
- **`res.json(body, statusCode)`**: Returns a JSON response with the appropriate `Content-Type` header. The second argument is the HTTP status code (defaults to `200`).
- **`log()` / `error()`**: Built-in logging utilities that write to the function's execution logs in the Appwrite Console.

## Example Usage

**Request:**
```bash
curl -X POST https://<APPWRITE_ENDPOINT>/functions/<FUNCTION_ID>/executions \
  -H "Content-Type: application/json" \
  -H "X-Appwrite-Project: <PROJECT_ID>" \
  -d '{"name": "Alice"}'
```

**Response (200):**
```json
{
  "ok": true,
  "greeting": "Hello, Alice! Welcome to Appwrite Functions!"
}
```

**Response when `name` is missing (400):**
```json
{
  "ok": false,
  "message": "Missing required field: \"name\""
}
```

## Project Structure

```
my-function/
├── src/
│   └── main.js        # The function code above
└── package.json
```

Minimal `package.json`:
```json
{
  "name": "greeting-function",
  "version": "1.0.0",
  "type": "module"
}
```

> **Note**: The `"type": "module"` field is required to use ES module `export default` syntax. The function file must be located at `src/main.js` by convention for Appwrite's Node.js runtime.

# Appwrite Storage: Create Bucket, Upload File & Get Preview

Here's a complete example using the Appwrite Web SDK:

## 1. Setup & Initialize

```javascript
import { Client, Storage, ID, Permission, Role, InputFile } from 'appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('YOUR_PROJECT_ID');

const storage = new Storage(client);
```

## 2. Create a Bucket (Server-Side with Node SDK)

> **Note:** Bucket creation requires an API key, so this is done server-side using the **Node SDK**.

```javascript
import { Client, Storage, Permission, Role } from 'node-appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('YOUR_PROJECT_ID')
    .setKey('YOUR_API_KEY');

const storage = new Storage(client);

async function createBucket() {
    try {
        const bucket = await storage.createBucket(
            ID.unique(),                // Bucket ID
            'images',                   // Bucket name
            [
                Permission.read(Role.any()),           // Anyone can read/view files
                Permission.create(Role.users()),       // Authenticated users can upload
                Permission.update(Role.users()),       // Authenticated users can update
                Permission.delete(Role.users()),       // Authenticated users can delete
            ],
            false,                      // fileSecurity (false = bucket-level permissions only)
            true,                       // enabled
            10 * 1024 * 1024,          // maximumFileSize (10MB)
            ['image/png', 'image/jpeg', 'image/gif', 'image/webp'],  // allowedFileExtensions
            'gzip',                     // compression
            true,                       // encryption
            false                       // antivirus
        );
        console.log('Bucket created:', bucket);
        return bucket;
    } catch (error) {
        console.error('Error creating bucket:', error);
    }
}

createBucket();
```

## 3. Upload a File (Client-Side Web SDK)

```javascript
const BUCKET_ID = 'YOUR_BUCKET_ID';

// Upload from a file input element
async function uploadFile(file) {
    try {
        const response = await storage.createFile(
            BUCKET_ID,
            ID.unique(),
            file,  // File object from <input type="file">
            [
                Permission.read(Role.any()),              // Anyone can view
                Permission.update(Role.user('USER_ID')),  // Only the owner can update
                Permission.delete(Role.user('USER_ID')),  // Only the owner can delete
            ]
        );
        console.log('File uploaded:', response);
        return response;
    } catch (error) {
        console.error('Upload error:', error);
    }
}

// Example: Bind to an HTML file input
document.getElementById('fileInput').addEventListener('change', async (event) => {
    const file = event.target.files[0];
    if (file) {
        const result = await uploadFile(file);
        if (result) {
            const previewUrl = getFilePreview(result.$id);
            document.getElementById('preview').src = previewUrl;
        }
    }
});
```

## 4. Get a File Preview URL

```javascript
function getFilePreview(fileId) {
    const result = storage.getFilePreview(
        BUCKET_ID,
        fileId,
        400,        // width
        300,        // height
        'center',   // gravity (crop position)
        90,         // quality (1-100)
        0,          // borderWidth
        '',         // borderColor
        0,          // borderRadius
        1,          // opacity (0-1)
        0,          // rotation (-360 to 360)
        '',         // background color
        'webp'      // output format: 'jpg', 'png', 'gif', 'webp'
    );
    console.log('Preview URL:', result);
    return result; // Returns a URL string
}
```

## 5. Additional Useful Operations

```javascript
// Get file details
async function getFileDetails(fileId) {
    const file = await storage.getFile(BUCKET_ID, fileId);
    console.log('File details:', file);
    return file;
}

// Get file for download
function getFileDownload(fileId) {
    return storage.getFileDownload(BUCKET_ID, fileId);
}

// Get file view (renders in browser)
function getFileView(fileId) {
    return storage.getFileView(BUCKET_ID, fileId);
}

// List all files in a bucket
async function listFiles() {
    const files = await storage.listFiles(BUCKET_ID);
    console.log('Files:', files);
    return files;
}

// Delete a file
async function deleteFile(fileId) {
    await storage.deleteFile(BUCKET_ID, fileId);
    console.log('File deleted');
}
```

## Key Points

| Concept | Details |
|---|---|
| **Bucket Permissions** | Set at bucket level; apply to all files when `fileSecurity` is `false` |
| **File Permissions** | Set per file during upload; only used when `fileSecurity` is `true` on the bucket |
| **`getFilePreview`** | Returns a **URL string** (not a promise) — works only for image files |
| **`getFileDownload`** | Returns a URL that triggers a browser download |
| **`getFileView`** | Returns a URL that renders the file in the browser |
| **Max file size** | Configurable per bucket; default is 30MB on Appwrite Cloud |

> **Important:** When `fileSecurity` is set to `false` on the bucket, only bucket-level permissions are enforced and file-level permissions are ignored. Set it to `true` if you need per-file permission granularity — in that case, **both** bucket-level and file-level permissions are evaluated (either one granting access is sufficient).

# Push Notifications with Appwrite Messaging

## Supported Push Notification Providers

Appwrite Messaging supports the following push notification providers:

- **FCM (Firebase Cloud Messaging)** — for Android and web
- **APNS (Apple Push Notification Service)** — for iOS/macOS
- **Huawei Push Kit** — for Huawei devices

---

## Setup Steps

### 1. Configure a Push Notification Provider

First, add a provider in the Appwrite Console:

**For FCM:**
- Go to **Messaging → Providers → Add Provider → Push → FCM**
- Upload your Firebase **Service Account JSON** file (obtained from Firebase Console → Project Settings → Service Accounts)

**For APNS:**
- Go to **Messaging → Providers → Add Provider → Push → APNS**
- Provide your **Bundle ID**, **Team ID**, **Key ID**, and **.p8 authentication key** file

### 2. Create a Topic

Topics allow you to group subscribers for targeted messaging:

```js
const { Client, Messaging } = require('node-appwrite');

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('<PROJECT_ID>')
    .setKey('<API_KEY>');

const messaging = new Messaging(client);

const topic = await messaging.createTopic(
    '[TOPIC_ID]',   // unique topic ID
    '[TOPIC_NAME]'  // human-readable name
);
```

### 3. Register Targets and Subscribe to Topics

On the client side, register the device for push notifications and create a push target:

```js
// Client-side SDK
import { Client, Account } from 'appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('<PROJECT_ID>');

const account = new Account(client);

// Create a push target for the logged-in user
const target = await account.createPushTarget(
    '[TARGET_ID]',      // unique target ID
    '[DEVICE_TOKEN]',   // FCM/APNS device token
    '[PROVIDER_ID]'     // optional: your provider ID
);
```

Then subscribe the target to a topic (server-side):

```js
const subscriber = await messaging.createSubscriber(
    '[TOPIC_ID]',       // topic ID
    '[SUBSCRIBER_ID]',  // unique subscriber ID
    '[TARGET_ID]'       // the push target ID
);
```

### 4. Send a Push Notification to a Topic

```js
const message = await messaging.createPush(
    '[MESSAGE_ID]',             // unique message ID
    '[NOTIFICATION_TITLE]',     // title
    '[NOTIFICATION_BODY]',      // body
    [],                         // topics: array of topic IDs
    [],                         // users: array of user IDs (optional)
    [],                         // targets: array of target IDs (optional)
    {                           // additional optional parameters
        // data: {},            // custom data payload
        // action: '',          // click action
        // image: '',           // notification image URL
        // icon: '',            // notification icon
        // sound: '',           // notification sound
        // tag: '',             // notification tag
        // badge: '',           // badge count
        // draft: false,        // save as draft
        // scheduledAt: '',     // schedule delivery (ISO 8601)
    }
);
```

**Example — sending to a topic:**

```js
const message = await messaging.createPush(
    ID.unique(),
    'New Feature Available!',
    'Check out our latest update with exciting new features.',
    ['announcements-topic'],  // send to this topic
);
```

---

## Key Concepts

| Concept | Description |
|---------|-------------|
| **Provider** | The push service (FCM, APNS, Huawei) configured in your project |
| **Target** | A specific device registered to receive push notifications |
| **Topic** | A group/channel that targets can subscribe to |
| **Subscriber** | A link between a target and a topic |

## Important Notes

- Users must be **authenticated** to register push targets.
- You can send to **topics**, **specific users**, or **individual targets**.
- Messages can be **scheduled** using the `scheduledAt` parameter with an ISO 8601 datetime.
- Messages can be saved as **drafts** by setting `draft: true`.
- Each platform (iOS, Android) requires its own provider configuration.
- On mobile, you need to integrate the respective platform SDK (Firebase, APNs) to obtain device tokens.

# `account.deleteSession()` vs `account.deleteSessions()`

## `account.deleteSession(sessionId)`

Deletes a **single specific session** identified by its session ID.

```javascript
// Log out from a specific session
await account.deleteSession('64a1b2c3d4e5f6');

// Log out from the CURRENT session
await account.deleteSession('current');
```

**Use cases:**
- **Logging out the current user** from the current device (using `'current'` as the session ID)
- **Revoking a specific session** — e.g., the user sees a list of active sessions and wants to revoke one from an unrecognized device
- Implementing a "Sign out" button in your app

---

## `account.deleteSessions()`

Deletes **all sessions** for the currently authenticated user across all devices.

```javascript
// Log out from ALL devices
await account.deleteSessions();
```

**Use cases:**
- **"Sign out everywhere"** functionality — when a user wants to log out from all devices at once
- **Security response** — if a user suspects their account is compromised and wants to invalidate all active sessions
- **Password change/reset flows** — after a password change, you may want to force re-authentication on all devices

---

## Key Differences at a Glance

| | `deleteSession(sessionId)` | `deleteSessions()` |
|---|---|---|
| **Scope** | Single session | All sessions |
| **Parameter** | Session ID (or `'current'`) | None |
| **Effect** | Targeted logout | Complete logout everywhere |
| **Typical use** | Standard "Log out" button | "Log out of all devices" |

## Practical Example

```javascript
// Standard logout button
async function logout() {
  await account.deleteSession('current');
  // Redirect to login page
}

// Security panel: "Sign out everywhere"
async function logoutEverywhere() {
  await account.deleteSessions();
  // Redirect to login page
}

// Revoke a specific session from a session management UI
async function revokeSession(sessionId) {
  await account.deleteSession(sessionId);
  // Refresh the sessions list
}
```

> **Tip:** Most apps will primarily use `account.deleteSession('current')` for their standard logout flow. Reserve `account.deleteSessions()` for security-sensitive actions where you need to invalidate all sessions at once.

# Subscribing to Multiple Channels with `client.subscribe()`

You can pass an array of channel strings to a single `subscribe()` call to listen to multiple resources simultaneously.

## Exact Channel Strings

- **Database collection documents:** `databases.[DATABASE_ID].collections.[COLLECTION_ID].documents`
- **Storage bucket files:** `buckets.[BUCKET_ID].files`

## Example

```javascript
const unsubscribe = client.subscribe(
  [
    'databases.myDatabaseId.collections.myCollectionId.documents',
    'buckets.myBucketId.files'
  ],
  (response) => {
    // Check which channel the event came from
    if (response.channels.includes('databases.myDatabaseId.collections.myCollectionId.documents')) {
      console.log('Document change:', response.payload);
    }

    if (response.channels.includes('buckets.myBucketId.files')) {
      console.log('File change:', response.payload);
    }

    // You can also inspect the specific event
    console.log('Event:', response.events);
  }
);

// Later, to stop listening:
unsubscribe();
```

## Key Details

- **First argument**: An **array of channel strings** (or a single string for one channel).
- **Second argument**: A **callback function** that receives a `response` object containing:
  - `response.events` — array of event strings (e.g., `databases.*.collections.*.documents.*.create`)
  - `response.channels` — array of channels that matched
  - `response.payload` — the affected resource (document or file object)

- The user must have **read permissions** on the target documents/files to receive realtime updates.
- Calling `unsubscribe()` closes **all** channels registered in that single `subscribe()` call.

# Subscribing to Realtime Document Changes and File Uploads with Appwrite Web SDK

Here's how to subscribe to multiple realtime channels simultaneously and handle each event type differently:

## Setup and Implementation

```javascript
import { Client, Databases, Storage } from 'appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('[YOUR_PROJECT_ID]');

const databases = new Databases(client);
const storage = new Storage(client);

// Subscribe to multiple channels at once
const unsubscribe = client.subscribe(
    [
        'databases.myDatabase.collections.myCollection.documents',
        'buckets.myBucket.files'
    ],
    (response) => {
        // Determine the event type from the response
        const events = response.events;

        // Handle document events
        if (events.some(event => event.includes('databases.') && event.includes('.documents.'))) {
            handleDocumentEvent(response);
        }

        // Handle file events
        if (events.some(event => event.includes('buckets.') && event.includes('.files.'))) {
            handleFileEvent(response);
        }
    }
);

// --- Document Event Handler ---
function handleDocumentEvent(response) {
    const events = response.events;
    const document = response.payload;

    if (events.some(event => event.endsWith('.create'))) {
        console.log('📄 New document created:', document.$id);
        console.log('   Data:', document);
        // e.g., append to a list in the UI
    }

    if (events.some(event => event.endsWith('.update'))) {
        console.log('✏️ Document updated:', document.$id);
        console.log('   Updated data:', document);
        // e.g., refresh the displayed data
    }

    if (events.some(event => event.endsWith('.delete'))) {
        console.log('🗑️ Document deleted:', document.$id);
        // e.g., remove from the UI
    }
}

// --- File Event Handler ---
function handleFileEvent(response) {
    const events = response.events;
    const file = response.payload;

    if (events.some(event => event.endsWith('.create'))) {
        console.log('📁 New file uploaded:', file.$id);
        console.log('   File name:', file.name);
        console.log('   File size:', file.sizeOriginal, 'bytes');
        console.log('   MIME type:', file.mimeType);
        // e.g., show a thumbnail or add to file list
    }

    if (events.some(event => event.endsWith('.update'))) {
        console.log('📝 File updated:', file.$id);
        console.log('   Updated name:', file.name);
        // e.g., refresh file metadata in the UI
    }

    if (events.some(event => event.endsWith('.delete'))) {
        console.log('🗑️ File deleted:', file.$id);
        // e.g., remove from file gallery
    }
}

// --- Cleanup ---
// Call unsubscribe() when you no longer need realtime updates
// e.g., on component unmount in React:
// useEffect(() => {
//     const unsubscribe = client.subscribe([...], callback);
//     return () => unsubscribe();
// }, []);
```

## React Component Example

```jsx
import { useEffect, useState } from 'react';
import { Client } from 'appwrite';

const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1')
    .setProject('[YOUR_PROJECT_ID]');

export default function RealtimeDashboard() {
    const [documents, setDocuments] = useState([]);
    const [files, setFiles] = useState([]);
    const [activityLog, setActivityLog] = useState([]);

    useEffect(() => {
        const unsubscribe = client.subscribe(
            [
                'databases.myDatabase.collections.myCollection.documents',
                'buckets.myBucket.files'
            ],
            (response) => {
                const { events, payload } = response;
                const timestamp = new Date().toLocaleTimeString();

                // Document events
                if (events.some(e => e.includes('.documents.'))) {
                    if (events.some(e => e.endsWith('.create'))) {
                        setDocuments(prev => [...prev, payload]);
                        setActivityLog(prev => [
                            { time: timestamp, msg: `Doc created: ${payload.$id}` },
                            ...prev
                        ]);
                    } else if (events.some(e => e.endsWith('.update'))) {
                        setDocuments(prev =>
                            prev.map(doc => doc.$id === payload.$id ? payload : doc)
                        );
                        setActivityLog(prev => [
                            { time: timestamp, msg: `Doc updated: ${payload.$id}` },
                            ...prev
                        ]);
                    } else if (events.some(e => e.endsWith('.delete'))) {
                        setDocuments(prev =>
                            prev.filter(doc => doc.$id !== payload.$id)
                        );
                        setActivityLog(prev => [
                            { time: timestamp, msg: `Doc deleted: ${payload.$id}` },
                            ...prev
                        ]);
                    }
                }

                // File events
                if (events.some(e => e.includes('.files.'))) {
                    if (events.some(e => e.endsWith('.create'))) {
                        setFiles(prev => [...prev, payload]);
                        setActivityLog(prev => [
                            { time: timestamp, msg: `File uploaded: ${payload.name}` },
                            ...prev
                        ]);
                    } else if (events.some(e => e.endsWith('.delete'))) {
                        setFiles(prev =>
                            prev.filter(file => file.$id !== payload.$id)
                        );
                        setActivityLog(prev => [
                            { time: timestamp, msg: `File deleted: ${payload.name}` },
                            ...prev
                        ]);
                    }
                }
            }
        );

        // Cleanup on unmount
        return () => unsubscribe();
    }, []);

    return (
        <div>
            <h2>Documents ({documents.length})</h2>
            <ul>
                {documents.map(doc => (
                    <li key={doc.$id}>{doc.$id}</li>
                ))}
            </ul>

            <h2>Files ({files.length})</h2>
            <ul>
                {files.map(file => (
                    <li key={file.$id}>{file.name} ({file.sizeOriginal} bytes)</li>
                ))}
            </ul>

            <h2>Activity Log</h2>
            <ul>
                {activityLog.map((entry, i) => (
                    <li key={i}>[{entry.time}] {entry.msg}</li>
                ))}
            </ul>
        </div>
    );
}
```

## Key Points

| Concept | Details |
|---|---|
| **Multiple channels** | Pass an array of channel strings to `client.subscribe()` |
| **Channel format** | `databases.[DB_ID].collections.[COL_ID].documents` for docs, `buckets.[BUCKET_ID].files` for files |
| **Event types** | Events end with `.create`, `.update`, or `.delete` |
| **Payload** | `response.payload` contains the full document or file object |
| **Cleanup** | Always call the returned `unsubscribe()` function when done (e.g., on component unmount) |
| **Permissions** | Users will only receive events for resources they have **read** permission on |

Here's a complete implementation using the Appwrite Web SDK (v1.4.x+):

```javascript
import { Client, Account, ID } from 'appwrite';

// 1. Initialize the client
const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Your API endpoint
    .setProject('YOUR_PROJECT_ID');              // Your project ID

// 2. Initialize the Account service
const account = new Account(client);

// 3. Sign up (Create account)
async function signUp(email, password, name = '') {
    try {
        const user = await account.create(
            ID.unique(),    // Unique ID for the user
            email,          // User email
            password,       // User password (min 8 chars)
            name            // Optional: user name
        );

        console.log('User created:', user);

        // Optional: Login immediately after signup
        await login(email, password);

        return user;
    } catch (error) {
        console.error('Signup error:', error.message);
        throw error;
    }
}

// 4. Login (Create session)
async function login(email, password) {
    try {
        const session = await account.createEmailPasswordSession(
            email,
            password
        );

        console.log('Session created:', session);

        // Session is automatically stored in cookies/localStorage
        // You can now access user data
        const user = await account.get();
        console.log('Current user:', user);

        return session;
    } catch (error) {
        console.error('Login error:', error.message);
        throw error;
    }
}

// 5. Get current user (check if logged in)
async function getCurrentUser() {
    try {
        const user = await account.get();
        return user;
    } catch (error) {
        // No active session
        return null;
    }
}

// 6. Logout
async function logout() {
    try {
        await account.deleteSession('current');
        console.log('Logged out successfully');
    } catch (error) {
        console.error('Logout error:', error.message);
    }
}

// Usage examples:
// signUp('user@example.com', 'password123', 'John Doe');
// login('user@example.com', 'password123');
```

**Key points:**

1. **Client setup**: Replace `YOUR_PROJECT_ID` with your Appwrite project ID. Use `https://cloud.appwrite.io/v1` for Appwrite Cloud or your self-hosted URL.

2. **Password requirements**: Appwrite requires passwords to be at least 8 characters by default (configurable in project settings).

3. **Session persistence**: The SDK automatically handles session cookies/storage. Once `createEmailPasswordSession` succeeds, subsequent requests are authenticated.

4. **User verification**: If email verification is enabled in your project, new users will have `emailVerification: false` until they verify their email.

```javascript
import { Client, Databases, ID } from 'appwrite';

// Initialize Appwrite client
const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Your API Endpoint
    .setProject('YOUR_PROJECT_ID'); // Your project ID

const databases = new Databases(client);

async function setupTasksDatabase() {
    try {
        // 1. Create Database
        const database = await databases.create(
            ID.unique(),      // Database ID
            'TasksDB'         // Name
        );
        console.log('Database created:', database.$id);

        // 2. Create Collection
        const collection = await databases.createCollection(
            database.$id,     // Database ID
            ID.unique(),      // Collection ID
            'tasks'           // Name
        );
        console.log('Collection created:', collection.$id);

        // 3. Create Attributes
        // Title (string, required, max 255 chars)
        await databases.createStringAttribute(
            database.$id,
            collection.$id,
            'title',
            255,      // size
            true      // required
        );

        // Completed (boolean, required)
        await databases.createBooleanAttribute(
            database.$id,
            collection.$id,
            'completed',
            true      // required
        );

        // Due Date (datetime, optional)
        await databases.createDatetimeAttribute(
            database.$id,
            collection.$id,
            'dueDate',
            false     // required (false = optional)
        );

        console.log('Attributes created');

        // 4. Insert a Document
        const document = await databases.createDocument(
            database.$id,
            collection.$id,
            ID.unique(),      // Document ID
            {
                title: 'Complete Appwrite integration',
                completed: false,
                dueDate: new Date('2024-12-31T23:59:00.000Z').toISOString()
            }
        );

        console.log('Document created:', document.$id);

    } catch (error) {
        console.error('Error:', error);
    }
}

// Execute
setupTasksDatabase();
```

**Important Notes:**

1. **Permissions**: Creating databases, collections, and attributes typically requires **Admin** or **Developer** role permissions. Ensure your API key or authenticated user has the necessary scope (`databases.write`, `collections.write`, `attributes.write`).

2. **Async Attributes**: Attribute creation is asynchronous. In production, you should poll the attribute status or wait before creating documents to ensure the schema is ready.

3. **Client vs Server**: While this uses the Web SDK, database/collection creation is often done server-side with an API key for security. The Web SDK is typically used for document operations (`createDocument`, `listDocuments`, etc.) on existing collections.

