    // Handle JSON parsing errors or unexpected issues
    error(err.message);
    return res.json(
      { success: false, message: 'Invalid JSON body or internal error.' },
      500
    );
  }
};
```

### Key Details:
1.  **Function Signature:** The modern Appwrite signature uses an object `{ req, res, log, error }`.
2.  **Request Parsing:** `req.body` is received as a raw string. `JSON.parse()` is required to access the `name` property.
3.  **Response Format:** `res.json()` is used to automatically set the Content-Type header to `application/json` and send the response.
4.  **Logging:** `log()` and `error()` are used to output information to the Appwrite Console logs, which is useful for debugging.

Here is the code to perform these actions using the Appwrite Web SDK.

**Note:** Creating a bucket is typically an administrative action. In a production environment, you should perform this step using a Server SDK (Node.js, PHP, etc.) with an API Key, or via the Appwrite Console. To run this code in the browser, your user account must have the `buckets.create` scope (e.g., a project owner or admin).

```javascript
import { Client, Storage, ID, Permission, Role } from "appwrite";

// 1. Initialize the SDK
const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Your Appwrite Endpoint
    .setProject('<YOUR_PROJECT_ID>');           // Your Project ID

const storage = new Storage(client);

async function manageStorage() {
    try {
        // 2. Create a Bucket
        // We configure permissions to allow any user (including unauthenticated) to read files,
        // but only authenticated users to create/update/delete.
        const bucket = await storage.createBucket(
            ID.unique(), // Bucket ID
            'My Images', // Bucket Name
            [
                Permission.read(Role.any()),      // Public read access
                Permission.create(Role.users()),  // Authenticated users can upload
                Permission.update(Role.users()),
                Permission.delete(Role.users())
            ],
            false, // fileSecurity: false (permissions are defined at bucket level)
            true,  // enabled
            10000000, // maximumFileSize (10MB)
            ['jpg', 'png', 'gif'] // allowedFileExtensions
        );

        const bucketId = bucket.$id;
        console.log(`Bucket created: ${bucketId}`);

        // 3. Upload a File
        // Assuming you have an HTML input element: <input type="file" id="fileInput" />
        const fileInput = document.getElementById('fileInput');

        if (fileInput.files.length > 0) {
            const file = fileInput.files[0];

            const uploadedFile = await storage.createFile(
                bucketId,
                ID.unique(), // File ID
                file
                // Note: If 'fileSecurity' was true in bucket creation, 
                // you would pass a permissions array here as the 4th argument.
            );

            const fileId = uploadedFile.$id;
            console.log(`File uploaded: ${fileId}`);

            // 4. Get Preview URL
            // This generates a URL to display the image. 
            // Since we allowed Role.any() to read, this URL works without an API key/session.
            const previewUrl = storage.getFilePreview(
                bucketId,
                fileId,
                800, // width (optional)
                600, // height (optional)
                'center', // gravity (optional)
                90 // quality (optional)
            );

            console.log(`Preview URL: ${previewUrl}`);

            // Example: Display the image
            const img = document.createElement('img');
            img.src = previewUrl;
            document.body.appendChild(img);

        } else {
            console.log("No file selected.");
        }

    } catch (error) {
        console.error("An error occurred:", error);
    }
}

manageStorage();
```

### Key Details

1.  **Permissions**:
    *   `Permission.read(Role.any())`: Makes files publicly accessible. This is required for the preview URL to work in an incognito window or for unauthenticated users.
    *   `Permission.create(Role.users())`: Restricts uploads to logged-in users.
2.  **fileSecurity**:
    *   Set to `false` in `createBucket` to inherit permissions from the bucket level.
    *   If set to `true`, you must pass a permissions array to `createFile` for every individual file uploaded.
3.  **getFilePreview**:
    *   This method returns a `URL` object. It supports transformation parameters (width, height, quality) specifically for images. If the file is not an image, this may return an error or a generic icon depending on the configuration.

To subscribe to document changes and file uploads simultaneously while handling them differently, you should create two separate subscriptions using the `client.subscribe` method. This allows you to attach distinct callback logic to each event type.

Here is the code implementation using the Appwrite Web SDK:

```javascript
import { Client } from 'appwrite';

// 1. Initialize the Client
const client = new Client()
    .setEndpoint('https://cloud.appwrite.io/v1') // Your API Endpoint
    .setProject('YOUR_PROJECT_ID');              // Your Project ID

// 2. Subscribe to Document Changes
// Replace 'YOUR_COLLECTION_ID' with the ID of the collection you want to watch
const documentSubscription = client.subscribe(
    'documents', 
    // For a specific collection, use: `collections.YOUR_COLLECTION_ID.documents`
    (response) => {
        // Handle Document Events
        if (response.events.includes('documents.create')) {
            console.log('New Document Created:', response.payload);
        } else if (response.events.includes('documents.update')) {
            console.log('Document Updated:', response.payload);
        } else if (response.events.includes('documents.delete')) {
            console.log('Document Deleted:', response.payload);
        }
    }
);

// 3. Subscribe to File Uploads
// Replace 'YOUR_BUCKET_ID' with the ID of your storage bucket
const fileSubscription = client.subscribe(
    'buckets.YOUR_BUCKET_ID.files', 
    (response) => {
        // Handle File Events
        if (response.events.includes('storage.files.create')) {
            console.log('File Uploaded:', response.payload);
            // Custom logic: e.g., update UI, show notification
        } else if (response.events.includes('storage.files.delete')) {
            console.log('File Deleted:', response.payload);
        }
    }
);

// Optional: Unsubscribe when no longer needed (e.g., component unmount)
// documentSubscription();
// fileSubscription();
```

### Key Details

1.  **Channels**:
    *   `'documents'`: Subscribes to all document changes in the project.
    *   `'collections.YOUR_COLLECTION_ID.documents'`: Subscribes to changes in a specific collection.
    *   `'buckets.YOUR_BUCKET_ID.files'`: Subscribes to file changes in a specific storage bucket.

2.  **Response Object**:
    *   `response.events`: An array of strings indicating what triggered the event (e.g., `documents.create`, `storage.files.create`).
    *   `response.payload`: The actual object data (the document or file metadata) involved in the event.

3.  **Separation of Concerns**: By creating two distinct subscription calls, you avoid complex `if/else` logic inside a single callback trying to distinguish between database and storage events. This makes the code cleaner and easier to maintain.

```javascript
client.subscribe(
    [
        'databases.[DATABASE_ID].collections.[COLLECTION_ID].documents',
        'storage.[BUCKET_ID].files'
    ],
    (response) => {
        console.log('Event received:', response);
    }
);
```

**The exact channel strings are:**

1.  **Database:** `databases.[DATABASE_ID].collections.[COLLECTION_ID].documents`
2.  **Storage:** `storage.[BUCKET_ID].files`

*Replace `[DATABASE_ID]`, `[COLLECTION_ID]`, and `[BUCKET_ID]` with your actual IDs.*

# Appwrite Email/Password Authentication (Web SDK)

## 1. Install Appwrite SDK

