# Appwrite Realtime Subscriptions - Documents & Files

Here's a complete example using the Appwrite Web SDK to subscribe to both document changes and file uploads with different event handling:

```javascript
import { Client, Databases, Storage, ID } from 'appwrite';

// Initialize Appwrite Client
const client = new Client()
  .setEndpoint('https://cloud.appwrite.io/v1')
  .setProject('your-project-id');

const databases = new Databases(client);
const storage = new Storage(client);

// Database and Collection IDs
const DATABASE_ID = 'your-database-id';
const COLLECTION_ID = 'your-collection-id';
const BUCKET_ID = 'your-bucket-id';

// Subscribe to Document Events
const documentSubscription = databases.subscribe(
  `databases.${DATABASE_ID}.collections.${COLLECTION_ID}.documents`,
  (response) => {
    console.log('📄 Document Event:', response);

    // Handle different document event types
    switch (response.events[0]) {
      case 'documents.*.create':
        console.log('✅ Document Created:', response.payload);
        // Handle creation logic (e.g., update UI, send notification)
        break;

      case 'documents.*.update':
        console.log('🔄 Document Updated:', response.payload);
        // Handle update logic (e.g., refresh cached data)
        break;

      case 'documents.*.delete':
        console.log('🗑️ Document Deleted:', response.payload);
        // Handle deletion logic (e.g., remove from UI)
        break;
    }
  }
);

// Subscribe to File Events
const fileSubscription = storage.subscribe(
  `buckets.${BUCKET_ID}.files`,
  (response) => {
    console.log('📁 File Event:', response);

    // Handle different file event types
    switch (response.events[0]) {
      case 'buckets.*.files.*.create':
        console.log('✅ File Uploaded:', response.payload);
        // Handle upload logic (e.g., show preview, update gallery)
        break;

      case 'buckets.*.files.*.delete':
        console.log('🗑️ File Deleted:', response.payload);
        // Handle deletion logic (e.g., remove from gallery)
        break;
    }
  }
);

// Optional: Subscribe to specific document
const specificDocSubscription = databases.subscribe(
  `databases.${DATABASE_ID}.collections.${COLLECTION_ID}.documents.${ID.unique()}`,
  (response) => {
    console.log('🎯 Specific Document Event:', response);
    // Handle events for this specific document only
  }
);

// Cleanup function (call when component unmounts or page closes)
function cleanup() {
  documentSubscription();
  fileSubscription();
  specificDocSubscription();
  console.log('🧹 All subscriptions cleaned up');
}

// Example: Call cleanup on page unload
window.addEventListener('beforeunload', cleanup);

// React Example (useEffect cleanup)
/*
useEffect(() => {
  const documentSubscription = databases.subscribe(...);
  const fileSubscription = storage.subscribe(...);

  return () => {
    documentSubscription();
    fileSubscription();
  };
}, []);
*/
```

## Key Points

| Feature | Description |
|---------|-------------|
| **Event Patterns** | Use wildcards (`*`) for broad subscriptions or specific IDs for targeted ones |
| **Event Types** | `create`, `update`, `delete` for documents; `create`, `delete` for files |
| **Payload** | `response.payload` contains the actual document/file data |
| **Cleanup** | Always unsubscribe to prevent memory leaks (call subscription function) |
| **Multiple Subs** | You can subscribe to multiple channels simultaneously |

